package types

import "time"

const (
	AgentRuntimeKind    = "AgentRuntime"
	CodeInterpreterKind = "CodeInterpreter"
	SandboxKind         = "Sandbox"
	SandboxClaimsKind   = "SandboxClaim"
)

type SandboxInfo struct {
	Kind             string              `json:"kind"`
	SandboxID        string              `json:"sandboxId"`
	SandboxNamespace string              `json:"sandboxNamespace"`
	Name             string              `json:"name"`
	EntryPoints      []SandboxEntryPoint `json:"entryPoints"`
	SessionID        string              `json:"sessionId"`
	CreatedAt        time.Time           `json:"createdAt"`
	ExpiresAt        time.Time           `json:"expiresAt"`
	Status           string              `json:"status"`
}

type SandboxEntryPoint struct {
	Path     string `json:"path"`
	Protocol string `json:"protocol"`
	Endpoint string `json:"endpoint"`
}

type CreateSandboxRequest struct {
	Kind      string `json:"kind"`
	Name      string `json:"name"`
	Namespace string `json:"namespace"`
}

func (car *CreateSandboxRequest) Validate() error {
	if car.Name == "" {
		return &ValidationError{Field: "name", Message: "name is required"}
	}
	if car.Namespace == "" {
		return &ValidationError{Field: "namespace", Message: "namespace is required"}
	}
	if car.Kind != AgentRuntimeKind && car.Kind != CodeInterpreterKind {
		return &ValidationError{Field: "kind", Message: "kind must be AgentRuntime or CodeInterpreter"}
	}
	return nil
}

type ValidationError struct {
	Field   string
	Message string
}

func (e *ValidationError) Error() string {
	return e.Message
}

type CreateSandboxResponse struct {
	SessionID   string              `json:"sessionId"`
	SandboxID   string              `json:"sandboxId"`
	SandboxName string              `json:"sandboxName"`
	EntryPoints []SandboxEntryPoint `json:"entryPoints"`
}

package store

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"strings"
	"time"

	redisv9 "github.com/redis/go-redis/v9"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"k8s.io/klog/v2"
)

const (
	sessionPrefix        = "session:"
	expiryIndexKey       = "session:expiry"
	lastActivityIndexKey = "session:last_activity"
)

type redisStore struct {
	cli                  *redisv9.Client
	sessionPrefix        string
	expiryIndexKey       string
	lastActivityIndexKey string
}

func newRedisStore() (Store, error) {
	opts, err := makeRedisOptions()
	if err != nil {
		return nil, err
	}
	cli := redisv9.NewClient(opts)
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	if err := cli.Ping(ctx).Err(); err != nil {
		return nil, fmt.Errorf("failed to connect to Redis: %v", err)
	}
	return &redisStore{
		cli:                  cli,
		sessionPrefix:        sessionPrefix,
		expiryIndexKey:       expiryIndexKey,
		lastActivityIndexKey: lastActivityIndexKey,
	}, nil
}

func makeRedisOptions() (*redisv9.Options, error) {
	redisAddr := os.Getenv("REDIS_ADDR")
	if redisAddr == "" {
		return nil, errors.New("REDIS_ADDR environment variable is not set")
	}
	redisPassword := os.Getenv("REDIS_PASSWORD")
	passwordRequired := os.Getenv("REDIS_PASSWORD_REQUIRED")
	if passwordRequired == "" {
		passwordRequired = "true"
	}
	if strings.ToLower(passwordRequired) != "false" && redisPassword == "" {
		return nil, errors.New("REDIS_PASSWORD is required when REDIS_PASSWORD_REQUIRED is not set to false")
	}
	return &redisv9.Options{
		Addr:     redisAddr,
		Password: redisPassword,
	}, nil
}

func (s *redisStore) Ping(ctx context.Context) error {
	result, err := s.cli.Ping(ctx).Result()
	if err != nil {
		return err
	}
	if result != "PONG" {
		return fmt.Errorf("unexpected ping response: %s", result)
	}
	return nil
}

func (s *redisStore) sessionKey(sessionID string) string {
	return s.sessionPrefix + sessionID
}

func (s *redisStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := s.sessionKey(sessionID)
	data, err := s.cli.Get(ctx, key).Result()
	if err != nil {
		if errors.Is(err, redisv9.Nil) {
			return nil, ErrNotFound
		}
		return nil, err
	}
	var sandbox types.SandboxInfo
	if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
		return nil, fmt.Errorf("failed to unmarshal sandbox: %v", err)
	}
	return &sandbox, nil
}

func (s *redisStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox cannot be nil")
	}
	if sandbox.ExpiresAt.IsZero() {
		return errors.New("ExpiresAt cannot be zero")
	}
	key := s.sessionKey(sandbox.SessionID)
	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %v", err)
	}
	pipe := s.cli.Pipeline()
	pipe.SetNX(ctx, key, data, 0)
	pipe.ZAdd(ctx, s.expiryIndexKey, redisv9.Z{
		Score:  float64(sandbox.ExpiresAt.Unix()),
		Member: sandbox.SessionID,
	})
	activityTime := time.Now()
	pipe.ZAdd(ctx, s.lastActivityIndexKey, redisv9.Z{
		Score:  float64(activityTime.Unix()),
		Member: sandbox.SessionID,
	})
	_, err = pipe.Exec(ctx)
	return err
}

func (s *redisStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox cannot be nil")
	}
	key := s.sessionKey(sandbox.SessionID)
	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %v", err)
	}
	ok, err := s.cli.SetXX(ctx, key, data, 0).Result()
	if err != nil {
		return err
	}
	if !ok {
		return ErrNotFound
	}
	return nil
}

func (s *redisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := s.sessionKey(sessionID)
	pipe := s.cli.Pipeline()
	pipe.Del(ctx, key)
	pipe.ZRem(ctx, s.expiryIndexKey, sessionID)
	pipe.ZRem(ctx, s.lastActivityIndexKey, sessionID)
	_, err := pipe.Exec(ctx)
	return err
}

func (s *redisStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}
	sessionIDs, err := s.cli.ZRangeByScore(ctx, s.expiryIndexKey, &redisv9.ZRangeBy{
		Min:   "-inf",
		Max:   fmt.Sprintf("%d", before.Unix()),
		Count: limit,
	}).Result()
	if err != nil {
		return nil, err
	}
	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (s *redisStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}
	sessionIDs, err := s.cli.ZRangeByScore(ctx, s.lastActivityIndexKey, &redisv9.ZRangeBy{
		Min:   "-inf",
		Max:   fmt.Sprintf("%d", before.Unix()),
		Count: limit,
	}).Result()
	if err != nil {
		return nil, err
	}
	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (s *redisStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return nil, nil
	}
	pipe := s.cli.Pipeline()
	cmds := make([]*redisv9.StringCmd, len(sessionIDs))
	for i, id := range sessionIDs {
		key := s.sessionKey(id)
		cmds[i] = pipe.Get(ctx, key)
	}
	_, err := pipe.Exec(ctx)
	if err != nil && !errors.Is(err, redisv9.Nil) {
		return nil, err
	}
	var results []*types.SandboxInfo
	for i, cmd := range cmds {
		data, err := cmd.Result()
		if err != nil {
			if errors.Is(err, redisv9.Nil) {
				klog.Warningf("session key not found for session ID: %s", sessionIDs[i])
				continue
			}
			return nil, err
		}
		var sandbox types.SandboxInfo
		if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
			klog.Warningf("failed to unmarshal sandbox for session ID %s: %v", sessionIDs[i], err)
			continue
		}
		results = append(results, &sandbox)
	}
	return results, nil
}

func (s *redisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return errors.New("session ID cannot be empty")
	}
	key := s.sessionKey(sessionID)
	exists, err := s.cli.Exists(ctx, key).Result()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}
	if at.IsZero() {
		at = time.Now()
	}
	return s.cli.ZAdd(ctx, s.lastActivityIndexKey, redisv9.Z{
		Score:  float64(at.Unix()),
		Member: sessionID,
	}).Err()
}

func (s *redisStore) Close() error {
	return s.cli.Close()
}

package store

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"strconv"
	"strings"
	"time"

	"github.com/valkey-io/valkey-go"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"k8s.io/klog/v2"
)

type valkeyStore struct {
	cli                  valkey.Client
	sessionPrefix        string
	expiryIndexKey       string
	lastActivityIndexKey string
}

func newValkeyStore() (Store, error) {
	opts, err := makeValkeyOptions()
	if err != nil {
		return nil, err
	}
	cli, err := valkey.NewClient(*opts)
	if err != nil {
		return nil, fmt.Errorf("failed to create Valkey client: %v", err)
	}
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	resp := cli.Do(ctx, cli.B().Ping().Build())
	if err := resp.Error(); err != nil {
		return nil, fmt.Errorf("failed to ping Valkey: %v", err)
	}
	return &valkeyStore{
		cli:                  cli,
		sessionPrefix:        sessionPrefix,
		expiryIndexKey:       expiryIndexKey,
		lastActivityIndexKey: lastActivityIndexKey,
	}, nil
}

func makeValkeyOptions() (*valkey.ClientOption, error) {
	valkeyAddr := os.Getenv("VALKEY_ADDR")
	if valkeyAddr == "" {
		return nil, errors.New("VALKEY_ADDR environment variable is not set")
	}
	valkeyPassword := os.Getenv("VALKEY_PASSWORD")
	passwordRequired := os.Getenv("VALKEY_PASSWORD_REQUIRED")
	if passwordRequired == "" {
		passwordRequired = "true"
	}
	if strings.ToLower(passwordRequired) != "false" && valkeyPassword == "" {
		return nil, errors.New("VALKEY_PASSWORD is required when VALKEY_PASSWORD_REQUIRED is not set to false")
	}
	opts := &valkey.ClientOption{
		InitAddress: strings.Split(valkeyAddr, ","),
		Password:    valkeyPassword,
	}
	if disableCache := os.Getenv("VALKEY_DISABLE_CACHE"); strings.ToLower(disableCache) == "true" {
		opts.DisableCache = true
	}
	if forceSingle := os.Getenv("VALKEY_FORCE_SINGLE"); strings.ToLower(forceSingle) == "true" {
		opts.ForceSingleClient = true
	}
	return opts, nil
}

func (s *valkeyStore) Ping(ctx context.Context) error {
	resp := s.cli.Do(ctx, s.cli.B().Ping().Build())
	if err := resp.Error(); err != nil {
		return err
	}
	result, err := resp.ToString()
	if err != nil {
		return err
	}
	if result != "PONG" {
		return fmt.Errorf("unexpected ping response: %s", result)
	}
	return nil
}

func (s *valkeyStore) sessionKey(sessionID string) string {
	return s.sessionPrefix + sessionID
}

func (s *valkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := s.sessionKey(sessionID)
	resp := s.cli.Do(ctx, s.cli.B().Get().Key(key).Build())
	if err := resp.Error(); err != nil {
		if valkey.IsValkeyNil(err) {
			return nil, ErrNotFound
		}
		return nil, err
	}
	data, err := resp.AsBytes()
	if err != nil {
		return nil, err
	}
	var sandbox types.SandboxInfo
	if err := json.Unmarshal(data, &sandbox); err != nil {
		return nil, fmt.Errorf("failed to unmarshal sandbox: %v", err)
	}
	return &sandbox, nil
}

func (s *valkeyStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox cannot be nil")
	}
	if sandbox.ExpiresAt.IsZero() {
		return errors.New("ExpiresAt cannot be zero")
	}
	key := s.sessionKey(sandbox.SessionID)
	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %v", err)
	}
	activityTime := time.Now()
	cmds := []valkey.Completed{
		s.cli.B().Setnx().Key(key).Value(string(data)).Build(),
		s.cli.B().Zadd().Key(s.expiryIndexKey).ScoreMember().ScoreMember(valkey.ScoreMember{
			Score:  float64(sandbox.ExpiresAt.Unix()),
			Member: sandbox.SessionID,
		}).Build(),
		s.cli.B().Zadd().Key(s.lastActivityIndexKey).ScoreMember().ScoreMember(valkey.ScoreMember{
			Score:  float64(activityTime.Unix()),
			Member: sandbox.SessionID,
		}).Build(),
	}
	for _, resp := range s.cli.DoMulti(ctx, cmds...) {
		if err := resp.Error(); err != nil {
			return err
		}
	}
	return nil
}

func (s *valkeyStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox cannot be nil")
	}
	key := s.sessionKey(sandbox.SessionID)
	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %v", err)
	}
	resp := s.cli.Do(ctx, s.cli.B().Set().Key(key).Value(string(data)).Xx().Build())
	if err := resp.Error(); err != nil {
		return err
	}
	result, err := resp.ToString()
	if err != nil {
		return err
	}
	if result != "OK" {
		return ErrNotFound
	}
	return nil
}

func (s *valkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := s.sessionKey(sessionID)
	cmds := []valkey.Completed{
		s.cli.B().Del().Key(key).Build(),
		s.cli.B().Zrem().Key(s.expiryIndexKey).Member(sessionID).Build(),
		s.cli.B().Zrem().Key(s.lastActivityIndexKey).Member(sessionID).Build(),
	}
	for _, resp := range s.cli.DoMulti(ctx, cmds...) {
		if err := resp.Error(); err != nil {
			return err
		}
	}
	return nil
}

func (s *valkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}
	resp := s.cli.Do(ctx, s.cli.B().Zrangebyscore().Key(s.expiryIndexKey).
		Min("-inf").Max(strconv.FormatInt(before.Unix(), 10)).
		Limit(0, limit).Build())
	if err := resp.Error(); err != nil {
		return nil, err
	}
	sessionIDs, err := resp.AsStrSlice()
	if err != nil {
		return nil, err
	}
	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (s *valkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}
	resp := s.cli.Do(ctx, s.cli.B().Zrangebyscore().Key(s.lastActivityIndexKey).
		Min("-inf").Max(strconv.FormatInt(before.Unix(), 10)).
		Limit(0, limit).Build())
	if err := resp.Error(); err != nil {
		return nil, err
	}
	sessionIDs, err := resp.AsStrSlice()
	if err != nil {
		return nil, err
	}
	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (s *valkeyStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return nil, nil
	}
	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = s.sessionKey(id)
	}
	resps := s.cli.DoMulti(ctx, s.cli.B().Mget().Key(keys...).Build()...)
	var results []*types.SandboxInfo
	for i, resp := range resps {
		if err := resp.Error(); err != nil {
			if valkey.IsValkeyNil(err) {
				klog.Warningf("session key not found for session ID: %s", sessionIDs[i])
				continue
			}
			return nil, err
		}
		data, err := resp.AsBytes()
		if err != nil {
			return nil, err
		}
		var sandbox types.SandboxInfo
		if err := json.Unmarshal(data, &sandbox); err != nil {
			klog.Warningf("failed to unmarshal sandbox for session ID %s: %v", sessionIDs[i], err)
			continue
		}
		results = append(results, &sandbox)
	}
	return results, nil
}

func (s *valkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return errors.New("session ID cannot be empty")
	}
	key := s.sessionKey(sessionID)
	resp := s.cli.Do(ctx, s.cli.B().Exists().Key(key).Build())
	if err := resp.Error(); err != nil {
		return err
	}
	exists, err := resp.AsInt64()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}
	if at.IsZero() {
		at = time.Now()
	}
	resp = s.cli.Do(ctx, s.cli.B().Zadd().Key(s.lastActivityIndexKey).ScoreMember().ScoreMember(valkey.ScoreMember{
		Score:  float64(at.Unix()),
		Member: sessionID,
	}).Build())
	return resp.Error()
}

func (s *valkeyStore) Close() error {
	s.cli.Close()
	return nil
}

package store

import (
	"fmt"
	"os"
	"strings"
	"sync"

	"k8s.io/klog/v2"
)

const (
	redisStoreType  string = "redis"
	valkeyStoreType string = "valkey"
)

var (
	initStoreOnce = &sync.Once{}
	provider      Store
)

func Storage() Store {
	initStoreOnce.Do(func() {
		if err := initStore(); err != nil {
			klog.Fatalf("init store failed: %v", err)
		}
	})
	return provider
}

func initStore() error {
	storeType := os.Getenv("STORE_TYPE")
	if storeType == "" {
		storeType = redisStoreType
	}
	storeType = strings.ToLower(storeType)

	var err error
	switch storeType {
	case redisStoreType:
		provider, err = newRedisStore()
	case valkeyStoreType:
		provider, err = newValkeyStore()
	default:
		return fmt.Errorf("unsupported STORE_TYPE: %s", storeType)
	}
	return err
}

