package workloadmanager

import (
	"context"
	"crypto/rand"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"errors"
	"fmt"
	"net/http"
	"os"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/google/uuid"
	"k8s.io/apimachinery/pkg/api/meta"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/runtime/schema"
	"k8s.io/client-go/dynamic"
	"k8s.io/client-go/kubernetes"
	"k8s.io/client-go/rest"
	"k8s.io/klog/v2"
	"sigs.k8s.io/controller-runtime/pkg/client"
	"sigs.k8s.io/controller-runtime/pkg/manager"

	"github.com/volcano-sh/agentcube/pkg/api"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
)

type Config struct {
	Port             string
	RuntimeClassName string
	EnableTLS        bool
	TLSCert          string
	TLSKey           string
	EnableAuth       bool
}

type Server struct {
	config            *Config
	router            *gin.Engine
	httpServer        *http.Server
	k8sClient         *K8sClient
	sandboxController *SandboxReconciler
	tokenCache        *TokenCache
	informers         *Informers
	storeClient       store.Store
	wg                sync.WaitGroup
}

type ErrorResponse struct {
	Message string `json:"message"`
}

func NewServer(config *Config) (*Server, error) {
	storeClient := store.Storage()
	k8sClient, err := NewK8sClient()
	if err != nil {
		return nil, fmt.Errorf("failed to create k8s client: %v", err)
	}
	informers, err := NewInformers(k8sClient)
	if err != nil {
		return nil, fmt.Errorf("failed to create informers: %v", err)
	}
	sandboxReconciler := NewSandboxReconciler(k8sClient.dynamicClient, k8sClient.scheme)
	s := &Server{
		config:            config,
		k8sClient:         k8sClient,
		sandboxController: sandboxReconciler,
		tokenCache:        NewTokenCache(1000, 5*time.Minute),
		informers:         informers,
		storeClient:       storeClient,
	}
	s.setupRouter()
	return s, nil
}

func (s *Server) setupRouter() {
	gin.SetMode(gin.ReleaseMode)
	s.router = gin.New()
	s.router.Use(gin.Recovery())
	s.router.GET("/health", s.handleHealth)
	v1 := s.router.Group("/v1")
	v1.Use(s.loggingMiddleware())
	if s.config.EnableAuth {
		v1.Use(s.authMiddleware())
	}
	v1.POST("/agent-runtime", s.handleAgentRuntimeCreate)
	v1.DELETE("/agent-runtime/sessions/:sessionId", s.handleDeleteSandbox)
	v1.POST("/code-interpreter", s.handleCodeInterpreterCreate)
	v1.DELETE("/code-interpreter/sessions/:sessionId", s.handleDeleteSandbox)
}

func (s *Server) loggingMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		c.Next()
		klog.Infof("[%s] %s %s %d %v", c.Request.Method, c.Request.URL.Path, c.ClientIP(), c.Writer.Status(), time.Since(start))
	}
}

func (s *Server) authMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.JSON(401, gin.H{"message": "Missing authorization header"})
			c.Abort()
			return
		}
		parts := splitAuthorization(authHeader)
		if len(parts) != 2 || parts[0] != "Bearer" {
			c.JSON(401, gin.H{"message": "Invalid authorization header format"})
			c.Abort()
			return
		}
		token := parts[1]
		userInfo, err := s.validateServiceAccountToken(c.Request.Context(), token)
		if err != nil {
			c.JSON(401, gin.H{"message": err.Error()})
			c.Abort()
			return
		}
		c.Set(string(contextKeyUserToken), token)
		c.Set(string(contextKeyServiceAccount), userInfo.username)
		c.Set(string(contextKeyServiceAccountName), userInfo.serviceAccountName)
		c.Set(string(contextKeyNamespace), userInfo.namespace)
		c.Next()
	}
}

func splitAuthorization(header string) []string {
	for i := 0; i < len(header); i++ {
		if header[i] == ' ' {
			return []string{header[:i], header[i+1:]}
		}
	}
	return []string{header}
}

func (s *Server) handleHealth(c *gin.Context) {
	c.JSON(200, gin.H{"status": "healthy"})
}

func (s *Server) handleAgentRuntimeCreate(c *gin.Context) {
	s.handleCreateSandbox(c, types.AgentRuntimeKind)
}

func (s *Server) handleCodeInterpreterCreate(c *gin.Context) {
	s.handleCreateSandbox(c, types.CodeInterpreterKind)
}

func (s *Server) handleCreateSandbox(c *gin.Context, kind string) {
	var sandboxReq types.CreateSandboxRequest
	if err := c.ShouldBindJSON(&sandboxReq); err != nil {
		c.JSON(400, ErrorResponse{Message: "Invalid request body"})
		return
	}
	sandboxReq.Kind = kind
	if err := sandboxReq.Validate(); err != nil {
		c.JSON(400, ErrorResponse{Message: err.Error()})
		return
	}
	ctx := c.Request.Context()
	sessionID := uuid.New().String()
	sandboxName := fmt.Sprintf("%s-%s", sandboxReq.Name, randString(8))
	sandboxID := uuid.New().String()
	var sandboxInfo *types.SandboxInfo
	var err error
	if kind == types.CodeInterpreterKind {
		sandboxInfo, err = s.createCodeInterpreterSandbox(ctx, &sandboxReq, sessionID, sandboxName, sandboxID)
	} else {
		sandboxInfo, err = s.createAgentRuntimeSandbox(ctx, &sandboxReq, sessionID, sandboxName, sandboxID)
	}
	if err != nil {
		if apiErr, ok := api.IsAPIStatus(err); ok {
			status := apiErr.Status()
			if status.Code == 0 {
				status.Code = 500
			}
			if status.Code == 500 {
				c.JSON(int(status.Code), ErrorResponse{Message: "internal server error"})
			} else {
				c.JSON(int(status.Code), ErrorResponse{Message: status.Message})
			}
		} else {
			c.JSON(500, ErrorResponse{Message: "internal server error"})
		}
		return
	}
	c.JSON(200, types.CreateSandboxResponse{
		SessionID:   sandboxInfo.SessionID,
		SandboxID:   sandboxInfo.SandboxID,
		SandboxName: sandboxInfo.Name,
		EntryPoints: sandboxInfo.EntryPoints,
	})
}

func (s *Server) createAgentRuntimeSandbox(ctx context.Context, req *types.CreateSandboxRequest, sessionID, sandboxName, sandboxID string) (*types.SandboxInfo, error) {
	return s.createSandboxFromTemplate(ctx, req, sessionID, sandboxName, sandboxID, types.AgentRuntimeKind)
}

func (s *Server) createCodeInterpreterSandbox(ctx context.Context, req *types.CreateSandboxRequest, sessionID, sandboxName, sandboxID string) (*types.SandboxInfo, error) {
	return s.createSandboxFromTemplate(ctx, req, sessionID, sandboxName, sandboxID, types.CodeInterpreterKind)
}

func (s *Server) createSandboxFromTemplate(ctx context.Context, req *types.CreateSandboxRequest, sessionID, sandboxName, sandboxID string, kind string) (*types.SandboxInfo, error) {
	template, err := s.getTemplate(ctx, req.Namespace, req.Name, kind)
	if err != nil {
		return nil, err
	}
	sandboxInfo := &types.SandboxInfo{
		Kind:             types.SandboxKind,
		SandboxID:        sandboxID,
		SandboxNamespace: req.Namespace,
		Name:             sandboxName,
		SessionID:        sessionID,
		CreatedAt:        time.Now(),
		ExpiresAt:        time.Now().Add(DefaultSandboxTTL),
		Status:           "pending",
	}
	if err := s.storeClient.StoreSandbox(ctx, sandboxInfo); err != nil {
		return nil, fmt.Errorf("failed to store sandbox placeholder: %v", err)
	}
	sandboxObj, err := s.buildSandboxObject(sandboxName, req.Namespace, template, kind)
	if err != nil {
		_ = s.storeClient.DeleteSandboxBySessionID(ctx, sessionID)
		return nil, err
	}
	notifyCh := make(chan SandboxStatusUpdate, 1)
	s.sandboxController.WatchSandboxOnce(req.Namespace, sandboxName, notifyCh)
	dynamicClient := s.k8sClient.dynamicClient
	if s.config.EnableAuth {
		token, _ := ctx.Value(contextKeyUserToken).(string)
		dynamicClient, err = s.k8sClient.GetOrCreateUserK8sClient(token, req.Namespace)
		if err != nil {
			_ = s.storeClient.DeleteSandboxBySessionID(ctx, sessionID)
			return nil, fmt.Errorf("failed to create user client: %v", err)
		}
	}
	_, err = dynamicClient.Resource(SandboxGVR).Namespace(req.Namespace).Create(ctx, sandboxObj, metav1.CreateOptions{})
	if err != nil {
		_ = s.storeClient.DeleteSandboxBySessionID(ctx, sessionID)
		return nil, fmt.Errorf("failed to create sandbox: %v", err)
	}
	select {
	case update := <-notifyCh:
		if update.Sandbox != nil && getSandboxStatus(update.Sandbox) == "running" {
			podIP, err := s.resolvePodIP(ctx, req.Namespace, sandboxName, update.Sandbox)
			if err != nil {
				s.deleteSandboxWithTimeout(ctx, dynamicClient, req.Namespace, sandboxName)
				_ = s.storeClient.DeleteSandboxBySessionID(ctx, sessionID)
				return nil, err
			}
			entryPoints := s.buildEntryPoints(template, podIP)
			sandboxInfo.EntryPoints = entryPoints
			sandboxInfo.Status = "running"
			_ = s.storeClient.UpdateSandbox(ctx, sandboxInfo)
			return sandboxInfo, nil
		}
	case <-time.After(2 * time.Minute):
		s.deleteSandboxWithTimeout(ctx, dynamicClient, req.Namespace, sandboxName)
		_ = s.storeClient.DeleteSandboxBySessionID(ctx, sessionID)
		return nil, errors.New("sandbox creation timed out")
	case <-ctx.Done():
		s.deleteSandboxWithTimeout(ctx, dynamicClient, req.Namespace, sandboxName)
		_ = s.storeClient.DeleteSandboxBySessionID(ctx, sessionID)
		return nil, ctx.Err()
	}
	s.deleteSandboxWithTimeout(ctx, dynamicClient, req.Namespace, sandboxName)
	_ = s.storeClient.DeleteSandboxBySessionID(ctx, sessionID)
	return nil, errors.New("sandbox did not reach running state")
}

func (s *Server) getTemplate(ctx context.Context, namespace, name, kind string) (interface{}, error) {
	var gvr schema.GroupVersionResource
	switch kind {
	case types.AgentRuntimeKind:
		gvr = AgentRuntimeGVR
	case types.CodeInterpreterKind:
		gvr = CodeInterpreterGVR
	default:
		return nil, fmt.Errorf("unknown kind: %s", kind)
	}
	obj, err := s.informers.GetTemplate(gvr, namespace, name)
	if err != nil {
		return nil, api.NewSandboxTemplateNotFoundError(namespace, name, kind)
	}
	return obj, nil
}

func (s *Server) handleDeleteSandbox(c *gin.Context) {
	sessionID := c.Param("sessionId")
	ctx := c.Request.Context()
	sandboxInfo, err := s.storeClient.GetSandboxBySessionID(ctx, sessionID)
	if err != nil {
		if errors.Is(err, store.ErrNotFound) {
			c.JSON(404, ErrorResponse{Message: fmt.Sprintf("Session ID %s not found, maybe already deleted", sessionID)})
			return
		}
		c.JSON(500, ErrorResponse{Message: "internal server error"})
		return
	}
	dynamicClient := s.k8sClient.dynamicClient
	if s.config.EnableAuth {
		token, _ := ctx.Value(contextKeyUserToken).(string)
		namespace, _ := ctx.Value(contextKeyNamespace).(string)
		dynamicClient, err = s.k8sClient.GetOrCreateUserK8sClient(token, namespace)
		if err != nil {
			c.JSON(500, ErrorResponse{Message: "internal server error"})
			return
		}
	}
	var gvr schema.GroupVersionResource
	if sandboxInfo.Kind == types.SandboxClaimsKind {
		gvr = SandboxClaimGVR
	} else {
		gvr = SandboxGVR
	}
	err = dynamicClient.Resource(gvr).Namespace(sandboxInfo.SandboxNamespace).Delete(ctx, sandboxInfo.Name, metav1.DeleteOptions{})
	if err != nil && !errors.Is(err, rest.ErrNamespaceNotFound) && !meta.IsNoMatchError(err) {
		c.JSON(500, ErrorResponse{Message: "internal server error"})
		return
	}
	_ = s.storeClient.DeleteSandboxBySessionID(ctx, sessionID)
	c.JSON(200, gin.H{"message": "Sandbox deleted successfully"})
}

func (s *Server) deleteSandboxWithTimeout(ctx context.Context, client dynamic.Interface, namespace, name string) {
	deleteCtx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer cancel()
	_ = client.Resource(SandboxGVR).Namespace(namespace).Delete(deleteCtx, name, metav1.DeleteOptions{})
}

func randString(n int) string {
	const letters = "abcdefghijklmnopqrstuvwxyz0123456789"
	b := make([]byte, n)
	rand.Read(b)
	for i := range b {
		b[i] = letters[int(b[i])%len(letters)]
	}
	return string(b)
}

func (s *Server) Start(ctx context.Context) error {
	if err := s.storeClient.Ping(ctx); err != nil {
		return fmt.Errorf("store ping failed: %v", err)
	}
	if err := s.informers.WaitForSync(ctx); err != nil {
		return fmt.Errorf("informers sync failed: %v", err)
	}
	s.wg.Add(1)
	go s.runGC(ctx)
	addr := ":" + s.config.Port
	s.httpServer = &http.Server{
		Addr:         addr,
		Handler:      s.router,
		ReadTimeout:  15 * time.Second,
		IdleTimeout:  90 * time.Second,
	}
	klog.Infof("Starting server on %s", addr)
	if s.config.EnableTLS {
		if s.config.TLSCert == "" || s.config.TLSKey == "" {
			return errors.New("TLS enabled but cert/key not provided")
		}
		return s.httpServer.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey)
	}
	return s.httpServer.ListenAndServe()
}

func (s *Server) Stop(ctx context.Context) error {
	shutdownCtx, cancel := context.WithTimeout(ctx, 15*time.Second)
	defer cancel()
	if err := s.httpServer.Shutdown(shutdownCtx); err != nil {
		return err
	}
	s.wg.Wait()
	return s.storeClient.Close()
}

func (s *Server) runGC(ctx context.Context) {
	defer s.wg.Done()
	ticker := time.NewTicker(15 * time.Second)
	defer ticker.Stop()
	gc := newGarbageCollector(s.k8sClient, s.storeClient, 15*time.Second)
	for {
		select {
		case <-ticker.C:
			gcCtx, cancel := context.WithTimeout(ctx, 2*time.Minute)
			gc.Run(gcCtx)
			cancel()
		case <-ctx.Done():
			return
		}
	}
}

type userInfo struct {
	username          string
	serviceAccountName string
	namespace         string
}

type contextKey string

const (
	contextKeyUserToken          contextKey = "userToken"
	contextKeyServiceAccount     contextKey = "serviceAccount"
	contextKeyServiceAccountName contextKey = "serviceAccountName"
	contextKeyNamespace          contextKey = "namespace"
)

const (
	IdentitySecretName   = "picod-router-identity"
	PublicKeyDataKey     = "public.pem"
	PrivateKeyDataKey    = "private.pem"
)

var IdentitySecretNamespace = "default"

func init() {
	if ns := os.Getenv("AGENTCUBE_NAMESPACE"); ns != "" {
		IdentitySecretNamespace = ns
	}
}

func TryStoreOrLoadJWTKeySecret(ctx context.Context, clientset kubernetes.Interface, privateKey *rsa.PrivateKey) error {
	if clientset == nil {
		config, err := rest.InClusterConfig()
		if err != nil {
			klog.Warningf("Not in cluster, skipping JWT key secret: %v", err)
			return nil
		}
		clientset, err = kubernetes.NewForConfig(config)
		if err != nil {
			return err
		}
	}
	secretClient := clientset.CoreV1().Secrets(IdentitySecretNamespace)
	_, err := secretClient.Get(ctx, IdentitySecretName, metav1.GetOptions{})
	if err == nil {
		return nil
	}
	privateKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: x509.MarshalPKCS1PrivateKey(privateKey),
	})
